mapper.select:
SELECT CAST(S.sermon_id AS VARCHAR) AS rqstNo , S.title AS title , S.content_html AS cont , S.author_id AS rqstId , S.preacher_name AS preacherName , S.scripture_reference AS scriptureReference , S.sermon_date AS sermonDate , S.worship_type AS worshipType , S.created_at AS insDt , S.updated_at AS uptDt , S.view_count AS views , 0 AS depth , NULL AS groupNo , CASE WHEN S.is_secret THEN 'Y' ELSE 'N' END AS secret , 'SERMONS' AS boardType , (SELECT COUNT(*) > 0 FROM official_sermon_file F WHERE F.sermon_id = S.sermon_id AND F.is_deleted = FALSE) AS hasFile , (SELECT COALESCE(SUM(file_size), 0) FROM official_sermon_file F WHERE F.sermon_id = S.sermon_id AND F.is_deleted = FALSE) AS totalFileSize , (SELECT COUNT(*) FROM official_sermon_comment C WHERE C.sermon_id = S.sermon_id AND C.is_deleted = FALSE AND C.parent_comment_id IS NULL) AS commentCount FROM official_sermon S WHERE S.is_deleted = FALSE
AND S.worship_type = #{worshipType}
AND S.title LIKE CONCAT('%', #{keyword}, '%')
AND S.content_text LIKE CONCAT('%', #{keyword}, '%')
AND S.author_id LIKE CONCAT('%', #{keyword}, '%')
AND S.worship_type = #{keyword}
AND (S.title LIKE CONCAT('%', #{keyword}, '%') OR S.content_text LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY S.created_at DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE official_sermon
   SET title = #{title}
     , content_html = #{cont}
                 , content_text = REGEXP_REPLACE(COALESCE(#{cont}, ''), '<[^>]*>', '', 'g')
                 , preacher_name = #{preacherName}
                 , scripture_reference = #{scriptureReference}
                 , sermon_date = NULLIF(#{sermonDate}, '')::date
                 , worship_type = #{worshipType}
     , is_secret = CASE WHEN COALESCE(#{secret}, 'N') = 'Y' THEN TRUE ELSE FALSE END
     , password_hash = COALESCE(#{password}, password_hash)
     , updated_at = NOW()
     , updated_by = COALESCE(NULLIF(#{rqstId}, ''), updated_by)
 WHERE sermon_id = #{rqstNo}
   AND is_deleted = FALSE

UPDATE official_sermon_comment
   SET like_count = like_count + 1
 WHERE sermon_comment_id = #{commentId}

UPDATE official_sermon_comment
   SET like_count = like_count - 1
 WHERE sermon_comment_id = #{commentId}

UPDATE official_sermon_comment
   SET dislike_count = dislike_count + 1
 WHERE sermon_comment_id = #{commentId}

UPDATE official_sermon_comment
   SET dislike_count = dislike_count - 1
 WHERE sermon_comment_id = #{commentId}
